const controlBase =
  'md:col-span-3 h-11 px-3 rounded-xl border transition-colors ' +
  'text-gray-900 dark:text-gray-100 ' +
  'bg-white dark:bg-slate-800/90 ' +
  'border-gray-200 dark:border-slate-600 ' +
  'placeholder:text-gray-500 dark:placeholder:text-gray-400 ' +
  'focus:outline-none focus:ring-2 focus:ring-brand-400/90 dark:focus:ring-brand-500/90 ' +
  'focus:border-brand-400 dark:focus:border-brand-500 ' +
  'shadow-sm dark:shadow-soft-dark';

const selectBase = `${controlBase} cursor-pointer dark:[color-scheme:dark]`;

const optionClass =
  'text-gray-900 bg-white dark:text-gray-100 dark:bg-slate-800';

export default function Filters({ cities, types, values, onChange }) {
  return (
    <div className="space-y-5">
      <div className="flex flex-col sm:flex-row sm:items-end sm:justify-between gap-2">
        <div className="flex items-start gap-3">
          <div className="mt-0.5 flex h-10 w-10 shrink-0 items-center justify-center rounded-xl bg-gradient-to-br from-brand-500/15 to-indigo-600/20 text-brand-600 dark:text-brand-400 ring-1 ring-brand-500/20">
            <svg
              className="h-5 w-5"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
              aria-hidden
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z"
              />
            </svg>
          </div>
          <div>
            <h2 className="text-lg font-bold text-gray-900 dark:text-white tracking-tight">
              Refine your search
            </h2>
            <p className="text-sm text-gray-500 dark:text-gray-400">
              City, workspace type, and price range
            </p>
          </div>
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-12 gap-3">
        <select
          className={selectBase}
          value={values.city}
          onChange={(e) => onChange({ ...values, city: e.target.value })}
          aria-label="City"
        >
          <option className={optionClass} value="">
            All cities
          </option>
          {cities.map((c) => (
            <option className={optionClass} key={c} value={c}>
              {c}
            </option>
          ))}
        </select>
        <select
          className={selectBase}
          value={values.type}
          onChange={(e) => onChange({ ...values, type: e.target.value })}
          aria-label="Workspace type"
        >
          <option className={optionClass} value="">
            All solutions
          </option>
          {types.map((t) => (
            <option className={optionClass} key={t} value={t}>
              {t}
            </option>
          ))}
        </select>
        <input
          type="number"
          min={0}
          placeholder="Min price (₹)"
          className={controlBase}
          value={values.minPrice}
          onChange={(e) => onChange({ ...values, minPrice: e.target.value })}
          aria-label="Minimum price per day"
        />
        <input
          type="number"
          min={0}
          placeholder="Max price (₹)"
          className={controlBase}
          value={values.maxPrice}
          onChange={(e) => onChange({ ...values, maxPrice: e.target.value })}
          aria-label="Maximum price per day"
        />
      </div>
    </div>
  );
}
